scwin.f_ReqFieldChk = async function () {
    //필수입력항목 체크
    // var passwd = "<%=userDto.getDecPasswd()%>";
    var passwd = scwin.passwd;
    // var oldPasswd = document.all.txt_oldPasswd.value.trim();
    var newPasswd = txt_newPasswd.getValue().trim();
    var confirmPasswd = txt_confirmPasswd.getValue().trim();

    if (newPasswd == "") {
        $c.gus.cfAlertMsg(MSG_LO_ERR_002);
        return false;
    }

    if (confirmPasswd == "") {
        $c.gus.cfAlertMsg(MSG_LO_ERR_003);
        return false;
    }

    if (newPasswd != confirmPasswd) {
        $c.gus.cfAlertMsg(MSG_LO_ERR_005);
        return false;
    }

    let passCheckVal = await scwin.f_passwordCheck(txt_userId.getValue(), newPasswd);

    if (!passCheckVal) {
        txt_newPasswd.focus();
        return false;
    }

    if (passwd == newPasswd) {
        $c.gus.cfAlertMsg(MSG_LO_ERR_004);
        return false;
    }
    return true;
}

scwin.f_passwordCheck = async function (vUserId, vPassword) {
    var iLen = vPassword.length;
    var engCnt = $c.gus.cfisEnglishCnt(vPassword);
    var numCnt = $c.gus.cfisNumberCnt(vPassword);

    if ($c.gus.cfnumChainChk(vPassword)) {
        $c.win.alert("비밀번호는 연속 또는 동일한  숫자 3자리 이상  사용할 수 없습니다.");
        return false;
    }

    if (iLen < 10) {
        $c.win.alert("비밀번호는 10자리 이상이어야 합니다.");
        return false;
    }

    let patternChk = await scwin.f_specialPatternCheck(vPassword)

    if (!patternChk) {
        $c.win.alert("비밀번호는 특수문자가 포함되어야 합니다.");
        return false;
    }

    if (engCnt == 0 || numCnt == 0) {
        $c.win.alert("비밀번호는 영어+숫자+특수문자 조합이어야 합니다.");
        return false;
    }

    if (vUserId == vPassword) {
        $c.win.alert("사용자ID를 비밀번호로 사용할  수  없습니다.");
        return false;
    }
    return true;
}


//특수문자 입력체크
scwin.f_specialPatternCheck = function (vPassword) {
    var special_pattern = /[`~!@#$%^&*|\\\'\";:\/?]/gi;

    if (special_pattern.test(vPassword) == true) {
        // alert('특수문자가 입력되었습니다.');
        return true;
    } else {
        return false;
    }
}

scwin.jsLogin = async function () {

    oGDS_login.set("userId", txt_userId.getValue());
    oGDS_login.set("passwd", txt_newPasswd.getValue());
    oGDS_login.set("passwdCheckCnt", 1);


    $c.sbm.execute(sbm_login); // tr_login.Post();


    // window.close();
}
//2022 2차인증 추가

//필수입력항목 체크
scwin.f_AuthReqFieldChk = function () {
    if (txt_userId.getValue() == "") {
        $c.gus.cfAlertMsg(MSG_LO_ERR_011);
        return false;
    }
    if (txt_userNm.getValue() == "") {
        $c.gus.cfAlertMsg(MSG_LO_ERR_012);
        return false;
    }
    if (txt_userMpNo.getValue() == "") {
        $c.gus.cfAlertMsg(MSG_LO_ERR_013);
        return false;
    } else {
        var vTelNo = txt_userMpNo.getValue();
        var regExp = /^(01[016789]{1}|02|0[3-9]{1}[0-9]{1})-?[0-9]{3,4}-?[0-9]{4}$/;

        if (!regExp.test(vTelNo)) {
            $c.gus.cfAlertMsg(MSG_LO_ERR_016);
            return;
        };

    }

    return true;
}

// 사용자 정보 확인
scwin.f_checkUserInfo = async function () {
    let validVal = await scwin.f_AuthReqFieldChk()
    if (validVal) {
        ds_user.set("userId", txt_userId.getValue());
        ds_user.set("userNm", txt_userNm.getValue());
        ds_user.set("userMpNo", txt_userMpNo.getValue());
        ds_user.set("chk", "3");
        ds_user.set("oldPasswd", txt_oldPasswd.getValue());

        $c.sbm.execute(sbm_retrieveUser); // tr_retrieveUser.post();        
    }
}

// 인증번호 전송
scwin.f_smsSend = async function () {
    $c.sbm.execute(sbm_saveAuthNo); // tr_saveAuthNo.post();
}

// 인증번호 확인
scwin.f_checkAuth = function () {

    if (scwin.vAuthNoYn == "N") {
        $c.gus.cfAlertMsg(MSG_LO_ERR_014);
        return false;
    }

    if (txt_autnNo.getValue() == "") {
        $c.gus.cfAlertMsg(MSG_LO_ERR_015);
        return false;
    }

    ds_confirm.set("authNo", txt_autnNo.getValue());
    ds_confirm.set("rcvNo", txt_userMpNo.getValue());
    ds_confirm.set("rcvNo2", txt_userMpNo.getValue());


    $c.sbm.execute(sbm_retrieveAuthNo); // tr_retrieveAuthNo.post();
}


scwin.now = new Date();
scwin.minute = scwin.now.getMinutes().toString();
scwin.second = scwin.now.getSeconds().toString();
scwin.minute = 5;
scwin.second = 00;
scwin.end = 0;

scwin.f_TimerCount = async function () {

    // 시간초과 후에는 뒤늦게 들어온 타이머도 전부 중지
    if (scwin.isTimerExpired) {
        txt_min.setValue("00");
        txt_secs.setValue("00");
        return;
    }

    if (scwin.second == 00) {
        scwin.minute = scwin.minute - 1;
        scwin.second = 59;
    } else {
        scwin.second = scwin.second - 1;
    }

    if ((scwin.minute < 0) && (scwin.end == 0)) {

        // 만료 상태로 전환
        scwin.isTimerExpired = true;

        // 화면은 00:00으로 고정
        scwin.minute = 0;
        scwin.second = 0;
        txt_min.setValue("00");
        txt_secs.setValue("00");

        if (scwin.vAuthNoYn == "Y" && !scwin.isAuthTimeoutAlertShown) {
            scwin.isAuthTimeoutAlertShown = true;   // 먼저 잠금
            await $c.win.alert("인증시간이 지났습니다.");
            window.close();
        }
        scwin.vAuthNoYn = "N";
        scwin.minute = 5;
        scwin.second = 00;
        return;
    }

    txt_min.setValue(0 + scwin.minute.toString());
    if (scwin.second < 10) {
        txt_secs.setValue(0 + scwin.second.toString());
    } else {
        txt_secs.setValue(scwin.second);
    }

    setTimeout(function () {
        scwin.f_TimerCount();
    }, 1000);
}


//숫자 입력 체크
scwin.f_onlyNum = function () {
    var key = e.keyCode;
    if (!(key == 8 || key == 9 || key == 13 || key == 46 || key == 144 || (key >= 48 && key <= 57) || key == 110 || key == 190)) {
        $c.win.alert('숫자만 입력 가능합니다');
        e.returnValue = false;
    }
}

scwin.sbm_saveEmp_submit = function (e) {
    oGDS_result_list.set("userId", txt_userId.getValue());
    oGDS_result_list.set("userNm", txt_userNm.getValue());
    oGDS_result_list.set("newPasswd", txt_newPasswd.getValue());
    oGDS_result_list.set("oldPasswd", txt_oldPasswd.getValue());
    oGDS_result_list.set("userMpNo", txt_userMpNo.getValue())
};

// for=tr_saveEmp event=OnSuccess()
scwin.sbm_saveEmp_submitdone = async function (e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
    await scwin.jsLogin();

    // // window.close();


};

scwin.resetFailureCount = function () {
    scwin.failedPasswordCount = 0;
};

scwin.handlePostLoginChecks = async function (userInfo) {
    if (String(userInfo.authLoginYn || "") !== "1") {
        return true;
    }

    const userMpNo = (userInfo.userMpNo || "").trim();
    const userMpNo2 = (userInfo.userMpNo2 || "").trim();

    if (!userMpNo && !userMpNo2) {
        await scwin.openUserMpNoPopup(userInfo);
        await $c.sbm.execute(sbm_logout);
        return false;
    }

    const authResult = await scwin.openAuthPopup(userInfo);
    if (authResult === "0") {
        return true;
    }

    await $c.sbm.execute(sbm_logout);
    return false;
};


scwin.clearPendingLoginPopup = function () {
    scwin.pendingLoginPopupType = "";
    scwin.pendingLoginPopupAlertSeen = false;
    scwin.pendingLoginPopupAlertClosed = false;
    scwin.pendingLoginPopupReady = true;
    $c.util.clearInterval(LOGIN_POPUP_WATCH_KEY);
    $c.util.clearTimeout(LOGIN_POPUP_OPEN_KEY);
};

scwin.applyLoginStorage = function (userInfo) {
    [
        "coClsCd",
        "privAdmin",
        "coCd",
        "userHomeClsCd",
        "userClsCd",
        "userId",
        "userNm",
        "empNo",
        "email",
        "lobranCd"
    ].forEach(function (key) {
        if (typeof userInfo[key] !== "undefined" && userInfo[key] !== null) {
            WebSquare.localStorage.setItem(key, userInfo[key]);
        }
    });

    let sysCd = userInfo.userClsCd;
    if (sysCd === "01") {
        sysCd = userInfo.userHomeClsCd;
        if (userInfo.coCd === "017") {
            sysCd = "LA";
        }
        if (!sysCd) {
            sysCd = "CM";
        }
    }

    if (sysCd) {
        WebSquare.localStorage.setItem("sysCd", sysCd);
    }
};


scwin.sbm_login_submitdone = async function (e) {

    const response = e.responseJSON;

    if (scwin.loginPopupLookupInProgress) {
        scwin.loginPopupLookupInProgress = false;
        const userInfo = response && response.OUT_GDS1 && response.OUT_GDS1.length > 0 ? response.OUT_GDS1[0] : null;
        sbm_login.action = "/login.do";
        scwin.userNm = userInfo && userInfo.userNm ? userInfo.userNm : "";
        txt_userId.setValue(scwin.userId);
        txt_userId.setDisabled(true);
        txt_userNm.setValue(scwin.userNm);
        txt_userNm.setDisabled(true);
        return;
    }

    scwin.loginAttemptInProgress = false;

    const result = response && response.resultDataSet ? response.resultDataSet[0] : null;

    if (!result) {
        location.href = "/error.html";
        return;
    }

    if (result.Msg === "SUCC" && response.OUT_GDS1 && response.OUT_GDS1.length > 0) {
        const userInfo = response.OUT_GDS1[0];

        scwin.resetFailureCount();

        const passed = await scwin.handlePostLoginChecks(userInfo);
        if (!passed) {
            txt_pwd.setValue("");
            txt_pwd.focus();
            return;
        }

        scwin.clearPendingLoginPopup();
        scwin.applyLoginStorage(userInfo);

        // 1. 부모 창의 주소를 변경
        // location.href = "/websquare/websquare.html?w2xPath=/ui/main/index.xml";
        window.opener.location.href = "/websquare/websquare.html?w2xPath=/ui/main/index.xml";

        // 2. 현재 팝업 창을 닫음
        window.close();
        return;
    }

    if (result.Msg === "FAIL") {
        await scwin.handleLoginFailure(scwin.getLoginErrorMessage(response));
        return;
    }

    location.href = "/error.html";
};



// <!-- 사용자확인 TR -->
// for=tr_retrieveUser event=OnSuccess()
scwin.sbm_retrieveUser_submitdone = async function (e) {
    let vExistYn = ds_userResult.getCellData(0, "useYn")
    if (vExistYn == "1") {
        await scwin.f_smsSend();
        // scwin.minute = 5;
        // scwin.second = 00;
        scwin.f_TimerCount();
    }
};

scwin.sbm_saveAuthNo_submit = function (e) {
    ds_condition.set("userId", txt_userId.getValue())
    ds_condition.set("userNm", txt_userNm.getValue())
    ds_condition.set("userMpNo", txt_userMpNo.getValue())
    ds_condition.set("rcvNo", txt_userMpNo.getValue())
};


// <!-- 인증번호전송 TR -->
// for=tr_saveAuthNo event=OnSuccess()
scwin.sbm_saveAuthNo_submitdone = function (e) {
    scwin.vAuthNoYn = "Y";
    scwin.isAuthTimeoutAlertShown = false;
    scwin.isTimerExpired = false;   // 새 인증전송 시 다시 타이머 동작 허용
};


// <!-- 인증확인 TR -->
// for=tr_retrieveAuthNo event=OnSuccess()
scwin.sbm_retrieveAuthNo_submitdone = function (e) {
    if (ds_result.getCellData(0, "authNo") != "") {
        scwin.f_Update();
    } else {
        $c.win.alert("유효하지 않은 인증번호입니다.");
        return;
    }
};

// 닫기 버튼 클릭 이벤트
scwin.btn_close_onclick = function (e) {
    $c.win.closePopup();
};
